/* Bounded Buffer - Producer Consumer Problem */
/* Initialization */
SEMAPHORE empty = N;    // Count of empty slots
SEMAPHORE full = 0;    // Count of filled slots
SEMAPHORE mutex = 1;    // Mutual exclusion for buffer

/* Producer Process */
PRODUCER()
BEGIN
    WHILE TRUE DO
        item = produce();
        wait(empty);       // Wait for empty slot
        wait(mutex);       // Enter critical section
        buffer[in] = item;
        in = (in + 1) % N;
        signal(mutex);     // Exit critical section
        signal(full);      // Indicate item produced
    END WHILE
END

/* Consumer Process */
CONSUMER()
BEGIN
    WHILE TRUE DO
        wait(full);        // Wait for item
        wait(mutex);       // Enter critical section
        item = buffer[out];
        out = (out + 1) % N;
        signal(mutex);     // Exit critical section
        signal(empty);     // Indicate slot empty
        consume(item);
    END WHILE
END

/* Dining Philosophers - Asymmetric Solution in C */
#include <stdio.h>
#include <pthread.h>
#include <semaphore.h>

#define N 5
sem_t forks[N];

void* philosopher(void* arg) {
    int id = *(int*)arg;

    while(1) {
        // Thinking
        printf("Philosopher %d is thinking\n", id);

        if(id % 2 == 0) {  // Even philosophers: right then left
            sem_wait(&forks[(id+1) % N]);
            sem_wait(&forks[id]);
        } else {           // Odd philosophers: left then right
            sem_wait(&forks[id]);
            sem_wait(&forks[(id+1) % N]);
        }

        // Eating
        printf("Philosopher %d is eating\n", id);
        sleep(1);

        // Put down forks
        sem_post(&forks[id]);
        sem_post(&forks[(id+1) % N]);
    }
}

int main() {
    pthread_t threads[N];
    int ids[N];

    // Initialize semaphores
    for(int i = 0; i < N; i++)
        sem_init(&forks[i], 0, 1);

    // Create philosopher threads
    for(int i = 0; i < N; i++) {
        ids[i] = i;
        pthread_create(&threads[i], NULL, philosopher, &ids[i]);
    }

    for(int i = 0; i < N; i++)
        pthread_join(threads[i], NULL);

    return 0;
}

import java.util.concurrent.*;

class SleepingBarber {
    private static final int CHAIRS = 5;
    private static final int CUSTOMERS = 20;

    // Semaphores
    private static Semaphore customers = new Semaphore(0);
    private static Semaphore barber = new Semaphore(0);
    private static Semaphore mutex = new Semaphore(1);

    private static int waiting = 0;

    public static void main(String[] args) {
        ExecutorService executor = Executors.newFixedThreadPool(10);

        // Start barber thread
        executor.submit(() -> barber());

        // Start customer threads
        for(int i = 0; i < CUSTOMERS; i++) {
            final int customerId = i;
            executor.submit(() -> customer(customerId));
        }

        executor.shutdown();
        executor.awaitTermination(60, TimeUnit.SECONDS);
    }

    static void barber() {
        while(true) {
            try {
                customers.acquire();    // Wait for customer
                mutex.acquire();
                waiting--;               // Customer sits in chair
                barber.release();        // Barber ready to cut
                mutex.release();

                // Cut hair
                System.out.println("Barber is cutting hair");
                Thread.sleep(1000);

            } catch(InterruptedException e) {
                e.printStackTrace();
            }
        }
    }

    static void customer(int id) {
        try {
            mutex.acquire();
            if(waiting < CHAIRS) {
                waiting++;
                System.out.println("Customer " + id + " is waiting. Waiting: " + waiting);
                customers.release();    // Signal customer arrived
                mutex.release();

                barber.acquire();        // Wait for barber
                System.out.println("Customer " + id + " is getting haircut");
            } else {
                System.out.println("Customer " + id + " left - no chairs available");
                mutex.release();
            }
        } catch(InterruptedException e) {
            e.printStackTrace();
        }
    }
}
